import{_ as e,o,c as r,a3 as d}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Markdown Toolbar Reference","description":"Every toolbar button in the Notely editor explained with keyboard shortcuts and usage notes.","frontmatter":{"title":"Markdown Toolbar Reference","description":"Every toolbar button in the Notely editor explained with keyboard shortcuts and usage notes.","keywords":"toolbar, markdown toolbar, shortcuts, headings, bold, italic, link, image, table, diagram","category":"Editor"},"headers":[],"relativePath":"editor/markdown-toolbar.md","filePath":"editor/markdown-toolbar.md","lastUpdated":1784665499000}'),a={name:"editor/markdown-toolbar.md"};function n(s,t,i,l,c,h){return o(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="toolbar-reference" tabindex="-1">Toolbar Reference <a class="header-anchor" href="#toolbar-reference" aria-label="Permalink to &quot;Toolbar Reference&quot;">​</a></h1><p>The Markdown toolbar sits above the editor and provides quick-insert actions for common Markdown elements.</p><h2 id="formatting-buttons" tabindex="-1">Formatting Buttons <a class="header-anchor" href="#formatting-buttons" aria-label="Permalink to &quot;Formatting Buttons&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Inserts</th><th>Notes</th></tr></thead><tbody><tr><td><strong>H1</strong> – <strong>H6</strong></td><td>Heading at cursor level</td><td>Wraps selection in heading if text is selected</td></tr><tr><td><strong>B</strong></td><td><code>**bold**</code></td><td>Wraps selection</td></tr><tr><td><strong>I</strong></td><td><code>*italic*</code></td><td>Wraps selection</td></tr><tr><td><strong>~~</strong></td><td><code>~~strikethrough~~</code></td><td>Wraps selection</td></tr><tr><td><strong>`</strong></td><td><code>`inline code`</code></td><td>Wraps selection</td></tr><tr><td><strong>&quot;</strong></td><td><code>&gt; blockquote</code></td><td>Prepends to current line</td></tr></tbody></table><h2 id="insert-buttons" tabindex="-1">Insert Buttons <a class="header-anchor" href="#insert-buttons" aria-label="Permalink to &quot;Insert Buttons&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Action</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Link</strong></td><td>Insert <code>[text](url)</code> template</td><td>Cursor lands on <code>url</code></td></tr><tr><td><strong>Image</strong></td><td>Open file picker → insert image</td><td>Uses workspace-relative path</td></tr><tr><td><strong>Table</strong></td><td>Insert 3×3 table skeleton</td><td>Opens inline table editor on click</td></tr><tr><td><strong>Ordered list</strong></td><td>Insert <code>1.</code> list item</td><td></td></tr><tr><td><strong>Unordered list</strong></td><td>Insert <code>-</code> list item</td><td></td></tr><tr><td><strong>Task</strong></td><td>Insert <code>- [ ]</code> task</td><td></td></tr><tr><td><strong>HR</strong></td><td>Insert <code>---</code></td><td></td></tr></tbody></table><h2 id="diagram-buttons" tabindex="-1">Diagram Buttons <a class="header-anchor" href="#diagram-buttons" aria-label="Permalink to &quot;Diagram Buttons&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Action</th></tr></thead><tbody><tr><td><strong>Mermaid</strong></td><td>Insert fenced Mermaid block</td></tr><tr><td><strong>Excalidraw</strong></td><td>Insert Excalidraw diagram block</td></tr></tbody></table><h2 id="validation-and-quality" tabindex="-1">Validation and Quality <a class="header-anchor" href="#validation-and-quality" aria-label="Permalink to &quot;Validation and Quality&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Action</th></tr></thead><tbody><tr><td><strong>Validate</strong></td><td>Run Markdown validation on the current note</td></tr><tr><td><strong>Format</strong></td><td>Auto-format the focused code block using Prettier</td></tr></tbody></table><h2 id="capture-button-windows" tabindex="-1">Capture Button (Windows) <a class="header-anchor" href="#capture-button-windows" aria-label="Permalink to &quot;Capture Button (Windows)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Action</th><th>Notes</th></tr></thead><tbody><tr><td><strong>📷 A</strong></td><td>Capture screen area — Auto Insert mode</td><td><code>A</code> = Auto Insert</td></tr><tr><td><strong>📷 R</strong></td><td>Capture screen area — Review Before Insert mode</td><td><code>R</code> = Review mode</td></tr></tbody></table><p>The mode badge (<code>A</code> or <code>R</code>) reflects the current setting from <strong>Settings → Screen Capture</strong>.</p><p>→ <a href="/workspace/screen-capture.html">Screen Capture guide</a></p><h2 id="view-mode-controls" tabindex="-1">View Mode Controls <a class="header-anchor" href="#view-mode-controls" aria-label="Permalink to &quot;View Mode Controls&quot;">​</a></h2><p>The mode buttons in the editor header bar (not the toolbar) control which view is shown:</p><table tabindex="0"><thead><tr><th>Button</th><th>Mode</th></tr></thead><tbody><tr><td><strong>Edit</strong></td><td>Raw Markdown editor</td></tr><tr><td><strong>Split</strong></td><td>Editor + live preview</td></tr><tr><td><strong>Preview</strong></td><td>Rendered output only</td></tr><tr><td><strong>Web</strong></td><td>Website-style rendering</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Keyboard Over Mouse</p><p>Most toolbar actions have keyboard alternatives. Open <strong>Help → Keyboard Shortcuts</strong> (<code>Ctrl + /</code>) for the full list.</p></div><div class="tip custom-block"><p class="custom-block-title">Wrapping Selections</p><p>Most formatting buttons (bold, italic, link, code) wrap the current text selection if one exists. Select text first for faster formatting.</p></div>',20)])])}const g=e(a,[["render",n]]);export{u as __pageData,g as default};
